import{_ as e,c as o,l as t,a as r,t as i,a4 as l,o as s}from"./chunks/framework.CzsDe1xi.js";const q=JSON.parse('{"title":"mysql 系统表空间","description":"","frontmatter":{"title":"mysql 系统表空间"},"headers":[],"relativePath":"doc/数据库/Mysql/基础/表空间/系统表空间.md","filePath":"packages/doc/src/数据库/Mysql/基础/表空间/系统表空间.md","lastUpdated":1711354439000}'),n={name:"doc/数据库/Mysql/基础/表空间/系统表空间.md"},d={id:"frontmatter-title",tabindex:"-1"},_=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),c=l('<h2 id="ibdata1" tabindex="-1">ibdata1 <a class="header-anchor" href="#ibdata1" aria-label="Permalink to &quot;ibdata1&quot;">​</a></h2><p>ibdata1是InnoDB的共有表空间，默认情况下会把表空间存放在一个文件ibdata1中，会造成这个文件越来越大。</p><p>发现问题所在之后，解决方法就是，使用独享表空间，将表空间分别单独存放。MySQL开启独享表空间的参数是Innodb_file_per_table，会为每个Innodb表创建一个.ibd的文件。</p><p>存储着以下内容：</p><ul><li><p><strong>表格数据页</strong></p></li><li><p><strong>表索引页</strong></p></li><li><p><strong>数据字典</strong></p></li><li><p><strong>MVCC控制数据</strong></p></li><li><ul><li><strong>撤消空间</strong></li><li><strong>回滚段</strong></li></ul></li></ul><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2>',6);function p(a,h,m,b,f,g){return s(),o("div",null,[t("h1",d,[r(i(a.$frontmatter.title)+" ",1),_]),c])}const y=e(n,[["render",p]]);export{q as __pageData,y as default};
